" S/4HANA CDS View example:
@AbapCatalog.sqlViewName: 'ZVENDOR_AGING_V'
@Analytics.query: true
define view ZVENDOR_AGING_CDS as
  select from acdoca
    inner join lfa1 on lfa1.lifnr = acdoca.lifnr
  {
    acdoca.bukrs, acdoca.lifnr, lfa1.name1,
    acdoca.hsl as amount, acdoca.prctr
  }
